mapper.select:
SELECT id, user_id, exercise_id, duration_minutes, intensity_level, intensity_factor, weight_kg_snapshot, total_calories, record_date, created_at FROM exercise_record WHERE user_id = #{userId}
AND ( record_date < #{cursorRecordDate} OR (record_date = #{cursorRecordDate} AND created_at < #{cursorCreatedAt}) OR (record_date = #{cursorRecordDate} AND created_at = #{cursorCreatedAt} AND id < #{cursorId}) )
ORDER BY record_date DESC, created_at DESC, id DESC LIMIT #{limit}
